/**
 * Location Selection Page
 * 
 * Allows user to select which location to install the app for
 * (Only shown if OAuth doesn't return locationId directly)
 */

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';

interface Location {
  id: string;
  name: string;
  address?: string;
}

export default function SelectLocationPage() {
  const router = useRouter();
  const [locations, setLocations] = useState<Location[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedLocation, setSelectedLocation] = useState<string | null>(null);
  const [installing, setInstalling] = useState(false);

  useEffect(() => {
    fetchLocations();
  }, []);

  const fetchLocations = async () => {
    try {
      const response = await fetch('/api/locations');
      
      if (!response.ok) {
        throw new Error('Failed to fetch locations');
      }

      const data = await response.json();
      setLocations(data.locations || []);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching locations:', err);
      setError(err instanceof Error ? err.message : 'Failed to load locations');
      setLoading(false);
    }
  };

  const handleInstall = async () => {
    if (!selectedLocation) return;

    setInstalling(true);

    try {
      const response = await fetch('/api/install-location', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          locationId: selectedLocation,
        }),
      });

      if (!response.ok) {
        throw new Error('Installation failed');
      }

      // Redirect to dashboard
      router.push('/dashboard');
    } catch (err) {
      console.error('Installation error:', err);
      setError(err instanceof Error ? err.message : 'Installation failed');
      setInstalling(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading locations...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="max-w-md w-full bg-white shadow-lg rounded-lg p-8">
          <div className="text-center">
            <div className="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-red-100">
              <svg
                className="h-6 w-6 text-red-600"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </div>
            <h3 className="mt-4 text-lg font-medium text-gray-900">Error</h3>
            <p className="mt-2 text-sm text-gray-500">{error}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-3xl mx-auto">
        <div className="bg-white shadow-lg rounded-lg overflow-hidden">
          <div className="px-6 py-8">
            <h2 className="text-2xl font-bold text-gray-900 mb-2">
              Select Location
            </h2>
            <p className="text-gray-600 mb-6">
              Choose which location you want to install DropTheFee Residuals for.
            </p>

            <div className="space-y-3">
              {locations.map((location) => (
                <div
                  key={location.id}
                  className={`border rounded-lg p-4 cursor-pointer transition-all ${
                    selectedLocation === location.id
                      ? 'border-blue-500 bg-blue-50'
                      : 'border-gray-200 hover:border-gray-300'
                  }`}
                  onClick={() => setSelectedLocation(location.id)}
                >
                  <div className="flex items-center">
                    <input
                      type="radio"
                      checked={selectedLocation === location.id}
                      onChange={() => setSelectedLocation(location.id)}
                      className="h-4 w-4 text-blue-600 focus:ring-blue-500"
                    />
                    <div className="ml-3">
                      <p className="text-sm font-medium text-gray-900">
                        {location.name}
                      </p>
                      {location.address && (
                        <p className="text-sm text-gray-500">{location.address}</p>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {locations.length === 0 && (
              <div className="text-center py-8">
                <p className="text-gray-500">No locations found</p>
              </div>
            )}

            <div className="mt-6">
              <button
                onClick={handleInstall}
                disabled={!selectedLocation || installing}
                className={`w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white ${
                  !selectedLocation || installing
                    ? 'bg-gray-400 cursor-not-allowed'
                    : 'bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500'
                }`}
              >
                {installing ? 'Installing...' : 'Install for Selected Location'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}